arguments.argument:
if global.gamePaused=false
{
  if fireProg=0
  {
    if y<targetY
    {
      y+=bulletSpeed
      if baseDir=0
        direction=315
      else
        direction=225
    }
    else
    {
      y-=bulletSpeed
      if baseDir=0
        direction=45
      else
        direction=135
    }
    
    if point_distance(0,y,0,targetY)<3
    {
      direction=baseDir
      fireProg+=1
    }
  }
  
  speed=bulletSpeed
  image_angle=direction
}
else
  speed=0
